create table injury_reports (
    injury_id       number generated by default as identity minvalue 1 maxvalue 9999999999999999999999999999 increment by 1 cache 20 noorder
    nocycle nokeep noscale not null enable,
    player_id       number not null enable,
    reported_date   date not null enable,
    injury_type     varchar2(80 byte) not null enable,
    severity_level  varchar2(20 byte) not null enable,
    expected_return date,
    medical_notes   varchar2(500 byte),
    report_status   varchar2(20 byte) default 'OPEN' not null enable
);

alter table injury_reports
    add constraint injury_reports_pk primary key ( injury_id )
        using index enable;

alter table injury_reports
    add constraint injury_severity_ck
        check ( severity_level in ( 'LOW', 'MEDIUM', 'HIGH' ) ) enable;

alter table injury_reports
    add constraint injury_status_ck
        check ( report_status in ( 'OPEN', 'CLEARED', 'MONITORING' ) ) enable;


